#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum SopVdbanalysisOperator {
    /// Gradient (Scalar->Vector)
    GradientScalarMinusVector = 0,
    /// Curvature (Scalar->Scalar)
    CurvatureScalarMinusScalar = 1,
    /// Laplacian (Scalar->Scalar)
    LaplacianScalarMinusScalar = 2,
    /// Closest Point (Scalar->Vector)
    ClosestPointScalarMinusVector = 3,
    /// Divergence (Vector->Scalar)
    DivergenceVectorMinusScalar = 4,
    /// Curl (Vector->Vector)
    CurlVectorMinusVector = 5,
    /// Length (Vector->Scalar)
    LengthVectorMinusScalar = 6,
    /// Normalize (Vector->Vector)
    NormalizeVectorMinusVector = 7,
}

